#include<bits/stdc++.h>
using namespace std;
int i,n,m,f,k[5005],s[5005],b[5005];
bool cmp(int x,int y){
    if(s[x]==s[y])return k[x]<k[y];
    return s[x]>s[y];
}
int main(void){
    cin>>n>>m;
    for(i=1;i<=n;i++)cin>>k[b[i]=i]>>s[i];
    sort(b+1,b+n+1,cmp);f=s[b[int(m*1.5)]];
    for(i=1;s[b[i]]>=f;i++);
	cout<<f<<' '<<i-1<<endl;
    for(i=1;s[b[i]]>=f;i++)cout<<k[b[i]]<<' '<<s[b[i]]<<endl;
    return false;
}
